"use client"

import * as React from "react"
import type { ColumnDef } from "@gunjo/ui"
import {
  DataTable,
  Badge,
  Delta,
  Meter,
  formatCurrency,
  formatNumber,
  formatPercent,
} from "@gunjo/ui"
import type { ComputedRouteRow, Eigyosho } from "./data"
import { ROUTES, EIGYOSHO_LIST } from "./data"

const oku = (yen: number) =>
  formatCurrency(yen, { compact: true, maximumFractionDigits: 1 })

const STATUS_BADGE: Record<
  ComputedRouteRow["status"],
  { variant: "success" | "warning" | "destructive"; label: string }
> = {
  黒字: { variant: "success", label: "黒字" },
  補助黒字: { variant: "warning", label: "補助黒字" },
  赤字: { variant: "destructive", label: "赤字" },
}

const columns: ColumnDef<ComputedRouteRow>[] = [
  {
    accessorKey: "keito",
    header: "系統",
    cell: ({ row }) => {
      const r = row.original
      return (
        <div className="min-w-[11rem]">
          <div className="flex items-center gap-2">
            <span className="font-semibold tabular-nums">{r.keito}</span>
            <Badge variant={STATUS_BADGE[r.status].variant}>
              {STATUS_BADGE[r.status].label}
            </Badge>
          </div>
          <div className="mt-0.5 text-xs text-muted-foreground">{r.name}</div>
          <div className="mt-0.5 text-[11px] text-muted-foreground">
            {r.eigyosho}・{r.daytype}
          </div>
        </div>
      )
    },
  },
  {
    accessorKey: "eigyoShunyu",
    header: "営業収入",
    cell: ({ getValue }) => (
      <span className="tabular-nums">{oku(getValue<number>())}</span>
    ),
  },
  {
    accessorKey: "hiyo",
    header: "営業費用",
    cell: ({ getValue }) => (
      <span className="tabular-nums text-muted-foreground">
        {oku(getValue<number>())}
      </span>
    ),
  },
  {
    accessorKey: "hojokin",
    header: "補助金",
    cell: ({ getValue }) => {
      const v = getValue<number>()
      return v > 0 ? (
        <span className="tabular-nums text-warning">{oku(v)}</span>
      ) : (
        <span className="text-muted-foreground">—</span>
      )
    },
  },
  {
    accessorKey: "soneki",
    header: "営業損益",
    cell: ({ row }) => {
      const r = row.original
      return (
        <div className="min-w-[8rem]">
          <Delta value={r.soneki} format={(v) => oku(v)} />
          {r.hojokin > 0 ? (
            <div className="mt-0.5 text-[11px] text-muted-foreground">
              補助除く {oku(r.sonekiExHojo)}
            </div>
          ) : null}
        </div>
      )
    },
  },
  {
    accessorKey: "eigyoKeisu",
    header: "営業係数",
    cell: ({ getValue }) => {
      const k = getValue<number>()
      const loss = k > 100
      // 営業係数は「低いほど良い・100超で赤字」。100 を基準に下回るほど健全。
      const meterValue = Math.max(0, Math.min(100, 100 - (k - 100)))
      return (
        <div className="min-w-[7.5rem]">
          <div className="flex items-baseline justify-between">
            <span
              className={
                "text-sm font-semibold tabular-nums " +
                (loss ? "text-destructive" : "text-success-strong")
              }
            >
              {formatNumber(k, { maximumFractionDigits: 1 })}
            </span>
            <span className="text-[11px] text-muted-foreground">
              {loss ? "赤字" : "黒字"}
            </span>
          </div>
          <Meter
            value={meterValue}
            max={100}
            size="inline"
            showValue={false}
            className="mt-1"
            aria-label={`営業係数 ${k}（${loss ? "赤字" : "黒字"}・100超で赤字）`}
            tone={loss ? "destructive" : "success"}
          />
        </div>
      )
    },
  },
  {
    accessorKey: "joshaNinin",
    header: "乗車人員",
    cell: ({ row }) => {
      const r = row.original
      const diff = r.joshaNinin - r.joshaNininPrev
      const pct = diff / r.joshaNininPrev
      return (
        <div className="min-w-[8rem]">
          <div className="tabular-nums">
            {formatNumber(r.joshaNinin)}
            <span className="ml-0.5 text-xs text-muted-foreground">人</span>
          </div>
          <div className="mt-0.5 text-[11px]">
            <span className="text-muted-foreground">前年比 </span>
            <Delta
              value={pct}
              format={(v) => formatPercent(v, { signed: true })}
            />
          </div>
        </div>
      )
    },
  },
]

export function RouteTable() {
  const [eigyosho, setEigyosho] = React.useState<Eigyosho | "全社">("全社")

  const rows = React.useMemo(
    () =>
      eigyosho === "全社"
        ? ROUTES
        : ROUTES.filter((r) => r.eigyosho === eigyosho),
    [eigyosho],
  )

  return (
    <DataTable<ComputedRouteRow, unknown>
      columns={columns}
      data={rows}
      filter={{ columnId: "keito", placeholder: "系統番号で絞り込み…" }}
      pageSize={10}
      pageSizeOptions={[10, 20, 50]}
      getRowState={(r) => (r.status === "赤字" ? "loss" : undefined)}
      headerActions={
        <div
          role="group"
          aria-label="営業所フィルタ"
          className="flex flex-wrap items-center gap-1"
        >
          {(["全社", ...EIGYOSHO_LIST] as const).map((opt) => {
            const active = eigyosho === opt
            return (
              <button
                key={opt}
                type="button"
                aria-pressed={active}
                onClick={() => setEigyosho(opt)}
                className={
                  "rounded-full border px-3 py-1 text-xs font-medium transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-ring " +
                  (active
                    ? "border-foreground bg-foreground text-background"
                    : "border-border bg-transparent text-foreground hover:bg-accent")
                }
              >
                {opt}
              </button>
            )
          })}
        </div>
      }
      labels={{
        filterPlaceholder: "系統番号で絞り込み…",
        noResults: "該当する系統がありません",
        rowsPerPage: "表示件数",
        paginationSummary: (from, to, total) =>
          `${total}系統中 ${from}–${to} を表示`,
      }}
    />
  )
}
